import React, { useState, useEffect } from "react";

export default function HomePage() {
  const [postsNotifications, setPostsNotifications] = useState([
    { id: 1, text: "Bạn của bạn đăng tin", read: false, visible: true },
    { id: 2, text: "Bạn có lời mời kết bạn mới", read: false, visible: true },
    { id: 3, text: "Ai đó bình luận bài viết của bạn", read: false, visible: true },
  ]);

  // Tự ẩn notification sau 3 giây
  useEffect(() => {
    const timers = postsNotifications.map(n => {
      if (n.visible && !n.read) {
        return setTimeout(() => {
          setPostsNotifications(prev =>
            prev.map(item =>
              item.id === n.id ? { ...item, visible: false } : item
            )
          );
        }, 3000);
      }
      return null;
    });
    return () => timers.forEach(t => t && clearTimeout(t));
  }, [postsNotifications]);

  const closeNotification = (id) => {
    setPostsNotifications(prev =>
      prev.map(n => n.id === id ? { ...n, visible: false, read: true } : n)
    );
  };

  const unreadCount = postsNotifications.filter(n => !n.read && n.visible).length;

  return (
    <div className="min-h-screen bg-white flex flex-col">
      {/* Header */}
      <div className="flex items-center justify-between bg-[#88BCF8] p-4 relative">
        <img
          src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/iitooitd_expires_30_days.png"
          className="w-36 h-32 object-contain"
        />
        <input
          placeholder="Nhập để tìm kiếm"
          className="text-black bg-[#F6FEFF] px-6 py-2 rounded-full w-1/3"
        />
        <div className="relative">
          <div className="relative cursor-pointer">
            <img
              src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/pt1vc4hr_expires_30_days.png"
              className="w-12 h-16"
            />
            {unreadCount > 0 && (
              <span className="absolute top-0 right-0 bg-red-500 text-white text-xs w-5 h-5 flex items-center justify-center rounded-full">
                {unreadCount}
              </span>
            )}
          </div>
        </div>
      </div>

      {/* Notification Container */}
      <div className="fixed top-16 right-6 flex flex-col items-end gap-2 z-50">
        {postsNotifications
          .filter(n => n.visible)
          .map((n) => (
            <div
              key={n.id}
              className="bg-[#FFDEF8CF] text-black px-4 py-2 rounded-xl shadow-lg flex items-center gap-4 w-80 transform transition-all duration-500 animate-slideDown"
            >
              <span className="flex-1">{n.text}</span>
              <button
                onClick={() => closeNotification(n.id)}
                className="text-black font-bold"
              >
                ×
              </button>
            </div>
          ))}
      </div>

      {/* CSS animation */}
      <style>
        {`
          @keyframes slideDown {
            0% { opacity: 0; transform: translateY(-20px); }
            10% { opacity: 1; transform: translateY(0); }
            90% { opacity: 1; transform: translateY(0); }
            100% { opacity: 0; transform: translateY(-20px); }
          }
          .animate-slideDown {
            animation: slideDown 3s forwards;
          }
        `}
      </style>

      {/* Body content */}
      <div className="p-4"> 
        <h1 className="text-2xl font-bold">Trang chủ</h1>
        <p>Đây là nội dung chính của trang chủ.</p>
      </div>
    </div>
  );
}
